class QueryResults[T]:
    """Helper class that allows both iteration and normal fetching of data from the db.

    Parameters
    ----------
    conn
        The connection object of type `ConnectionLike` used to execute queries.
    sql
        The SQL statement that will be executed when fetching/iterating.
    decode_hook
        A callback that turns an `psycopg.rows.TupleRow` object into `T` that will be returned.
    params
        Named arguments that should be sent when executing the sql query.

    """

    __slots__ = ("_conn", "_cursor", "_decode_hook", "_iterator", "_params", "_sql")

    def __init__(
        self,
        conn: ConnectionLike,
        sql: typing.LiteralString,
        decode_hook: collections.abc.Callable[[psycopg.rows.TupleRow], T],
        params: dict[str, QueryResultsArgsType] | None = None,
    ) -> None:
        """Initialize the QueryResults instance."""
        self._conn = conn
        self._sql: typing.LiteralString = sql
        self._decode_hook = decode_hook
        self._params = params
        self._cursor: psycopg.AsyncCursor[psycopg.rows.TupleRow] | None = None
        self._iterator: collections.abc.AsyncIterator[psycopg.rows.TupleRow] | None = None

    def __aiter__(self) -> QueryResults[T]:
        """Initialize iteration support for `async for`.

        Returns
        -------
        QueryResults[T]
            Self as an asynchronous iterator.
        """
        return self

    def __await__(
        self,
    ) -> collections.abc.Generator[None, None, collections.abc.Sequence[T]]:
        """Allow `await` on the object to return all rows as a fully decoded sequence.

        Returns
        -------
        collections.abc.Sequence[T]
            A sequence of decoded objects of type `T`.
        """

        async def _wrapper() -> collections.abc.Sequence[T]:
            result = await (await self._conn.execute(self._sql, self._params)).fetchall()
            return [self._decode_hook(row) for row in result]

        return _wrapper().__await__()

    async def __anext__(self) -> T:
        """Yield the next item in the query result using a psycopg cursor.

        Returns
        -------
        T
            The next decoded result.

        Raises
        ------
        StopAsyncIteration
            When no more records are available.
        """
        if self._cursor is None or self._iterator is None:
            self._cursor = await self._conn.execute(self._sql, self._params)
            self._iterator = self._cursor.__aiter__()
        try:
            record = await self._iterator.__anext__()
        except StopAsyncIteration:
            self._cursor = None
            self._iterator = None
            raise
        return self._decode_hook(record)


